import urllib.request, urllib.error
from urllib.parse import urljoin
base='http://localhost:80/'
paths=['cgi-bin/','cgi-bin/test','server-status','server-info','icons/','manual/','hidden/','admin/','backup/','backups/','old/','test/','dev/','private/','secret/','secrets/','.git/','.svn/','.htaccess','.htpasswd','flag','flag.txt','FLAG','FLAG.txt','robots.txt','uploads/','upload/','api/','debug/','phpinfo.php','index.php','index.html','index.cgi','contact','contact.php','assets/','images/','img/','dev1.jpeg','dev2.jpeg','styles.css','scripts.js','nas/','NAS/','Modernizer/','modernizer/','modernizer200/','modernizer-200/','nas.zip','backup.zip','site.zip','website.zip','site.tar.gz','backup.tar.gz']
for p in paths:
    url=urljoin(base,p)
    try:
        req=urllib.request.Request(url,method='GET')
        with urllib.request.urlopen(req,timeout=5) as r:
            code=r.getcode(); ct=r.headers.get('Content-Type','')
            print(code,p,ct)
    except urllib.error.HTTPError as e:
        if e.code not in (404,405):
            print('H',e.code,p)
    except Exception as e:
        pass

